using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Shared state for the note-taking tool
// ---------------------------------------------------------------------------
var notes = new List<string>();

// ---------------------------------------------------------------------------
// Tool definitions
// ---------------------------------------------------------------------------
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb, "SearchWeb",
        "Searches the web for a query and returns a list of result snippets."),
    AIFunctionFactory.Create(AddNote, "AddNote",
        "Saves a research note for later reference."),
    AIFunctionFactory.Create(GetNotes, "GetNotes",
        "Returns all research notes collected so far."),
};

// ---------------------------------------------------------------------------
// Build the chat client
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(openAiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = tools };

// ---------------------------------------------------------------------------
// System prompt
// ---------------------------------------------------------------------------
var systemPrompt = """
    You are a research agent. Given a topic you must:
    1. Search the web for relevant information (make several varied queries).
    2. Save the most important findings as notes using the AddNote tool.
    3. After you have gathered enough information, retrieve your notes and
       produce a well-structured markdown summary with sections and citations.
    Be thorough: use at least 3 different search queries before summarizing.
    """;

// ---------------------------------------------------------------------------
// Interactive loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research the following topic and provide a summary:\n\n{topic}"),
    };

    Console.WriteLine("\nResearching… (this may take a moment)\n");

    var response = await chatClient.GetResponseAsync(messages, chatOptions);
    Console.WriteLine(response.Text);
    Console.WriteLine();
}

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

[Description("Searches the web for a query and returns result snippets.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    Console.ResetColor();

    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (Console; .NET 10)");

        // Use DuckDuckGo Instant Answer API (free, no key required)
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        var json = await http.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        // Abstract
        var abs = json.GetProperty("Abstract").GetString();
        if (!string.IsNullOrWhiteSpace(abs))
            results.Add($"[Summary] {abs} (source: {json.GetProperty("AbstractURL").GetString()})");

        // Related topics
        if (json.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var t in topics.EnumerateArray().Take(5))
            {
                var text = t.TryGetProperty("Text", out var tv) ? tv.GetString() : null;
                var link = t.TryGetProperty("FirstURL", out var lu) ? lu.GetString() : null;
                if (!string.IsNullOrWhiteSpace(text))
                    results.Add($"• {text} ({link})");
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : $"No detailed results found for \"{query}\". Try a different query.";
    }
    catch (Exception ex)
    {
        return $"Search failed ({ex.Message}). Try a different query.";
    }
}

[Description("Saves a research note.")]
string AddNote(
    [Description("The note content to save")] string note)
{
    notes.Add(note);
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📝 Note saved ({notes.Count} total)");
    Console.ResetColor();
    return $"Note saved. You now have {notes.Count} note(s).";
}

[Description("Returns all saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  📋 Retrieving {notes.Count} note(s)");
    Console.ResetColor();

    return string.Join("\n---\n",
        notes.Select((n, i) => $"Note {i + 1}: {n}"));
}

